  1	import * as React from 'react';
  2	import { LSO_OPERATOR } from '@odf/core/constants';
  3	import { ExternalSystemsSelectModal } from '@odf/core/modals/ConfigureDF/ExternalSystemsModal';
  4	import { FDF_FLAG } from '@odf/core/redux';
  5	import { storageClusterResource } from '@odf/core/resources';
  6	import {
  7	  DEFAULT_INFRASTRUCTURE,
  8	  InfrastructureKind,
  9	  StorageClusterKind,
 10	  useFetchCsv,
 11	  useK8sGet,
 12	} from '@odf/shared';
 13	import {
 14	  useCustomPrometheusPoll,
 15	  usePrometheusBasePath,
 16	} from '@odf/shared/hooks/custom-prometheus-poll';
 17	import {
 18	  SAN_CLUSTER_NAME_ANNOTATION,
 19	  useWatchStorageSystems,
 20	} from '@odf/shared/hooks/useWatchStorageSystems';
 21	import { Kebab } from '@odf/shared/kebab/kebab';
 22	import {
 23	  IBMFlashSystemModel,
 24	  InfrastructureModel,
 25	  RemoteClusterModel,
 26	  ODFStorageSystem,
 27	  StorageClusterModel,
 28	  ClusterModel,
 29	  FileSystemModel,
 30	} from '@odf/shared/models';
 31	import { getName, getNamespace } from '@odf/shared/selectors';
 32	import { Status } from '@odf/shared/status/Status';
 33	import { HumanizeResult, StorageSystemKind } from '@odf/shared/types';
 34	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 35	import {
 36	  humanizeBinaryBytes,
 37	  humanizeDecimalBytesPerSec,
 38	  humanizeIOPS,
 39	  humanizeLatency,
 40	  referenceForGroupVersionKind,
 41	  referenceForModel,
 42	  getGVK,
 43	  isCSVSucceeded,
 44	} from '@odf/shared/utils';
 45	import {
 46	  K8sModel,
 47	  ListPageBody,
 48	  ListPageFilter,
 49	  ListPageHeader,
 50	  PrometheusEndpoint,
 51	  PrometheusResponse,
 52	  RowProps,
 53	  TableColumn,
 54	  TableData,
 55	  useActiveColumns,
 56	  useFlag,
 57	  useK8sWatchResource,
 58	  useListPageFilter,
 59	  useModal,
 60	  VirtualizedTable,
 61	} from '@openshift-console/dynamic-plugin-sdk';
 62	import classNames from 'classnames';
 63	import * as _ from 'lodash-es';
 64	import { Button } from '@patternfly/react-core';
 65	import { sortable, wrappable } from '@patternfly/react-table';
 66	import {
 67	  ODF_QUERIES,
 68	  ODFQueries,
 69	  SCALE_QUERIES,
 70	  ScaleQueries,
 71	  ScaleHealthStatus,
 72	} from '../../queries';
 73	import { useODFNamespaceSelector } from '../../redux';
 74	import { FileSystemKind } from '../../types/scale';
 75	import { OperandStatus } from '../utils';
 76	import { getActions } from './actions';
 77	import ODFSystemLink from './system-link';
 78	
 79	type SystemMetrics = {
 80	  [systemNameAndNamespace: string]: {
 81	    rawCapacity: HumanizeResult;
 82	    usedCapacity: HumanizeResult;
 83	    iops: HumanizeResult;
 84	    throughput: HumanizeResult;
 85	    latency: HumanizeResult;
 86	    healthStatus?: string;
 87	  };
 88	};
 89	
 90	type MetricSet = {
 91	  latency: PrometheusResponse;
 92	  throughput: PrometheusResponse;
 93	  rawCapacity: PrometheusResponse;
 94	  usedCapacity: PrometheusResponse;
 95	  iops: PrometheusResponse;
 96	  health?: PrometheusResponse;
 97	};
 98	
 99	type FilesystemsByRemoteCluster = {
100	  [remoteClusterName: string]: string[];
101	};
102	
103	const EMPTY_METRIC: HumanizeResult = { string: '-', value: 0, unit: '' };
104	
105	const getHealthStatusFromMetric = (
106	  healthValue: number | undefined
107	): string | undefined => {
108	  if (healthValue === undefined || Number.isNaN(healthValue)) {
109	    return undefined;
110	  }
111	  if (healthValue <= ScaleHealthStatus.HEALTHY) {
112	    return 'Ready';
113	  }
114	  if (healthValue <= ScaleHealthStatus.DEGRADED) {
115	    return 'Warning';
116	  }
117	  return 'Error';
118	};
119	
120	type MetricNormalize = (
121	  systems: StorageSystemKind[],
122	  odfMetrics: MetricSet,
123	  scaleMetrics: MetricSet,
124	  filesystemsByRemoteCluster: FilesystemsByRemoteCluster
125	) => SystemMetrics;
126	
127	export const normalizeMetrics: MetricNormalize = (
128	  systems,
129	  odfMetrics,
130	  scaleMetrics,
131	  filesystemsByRemoteCluster
132	) => {
133	  if (_.isEmpty(systems)) {
134	    return {};
135	  }
136	
137	  const hasMetrics = (metrics: MetricSet): boolean =>
138	    !!(
139	      metrics.latency ||
140	      metrics.throughput ||
141	      metrics.rawCapacity ||
142	      metrics.usedCapacity ||
143	      metrics.iops ||
144	      metrics.health
145	    );
146	
147	  if (!hasMetrics(odfMetrics) && !hasMetrics(scaleMetrics)) {
148	    return {};
149	  }
150	
151	  const getHumanizedMetric = (
152	    humanizeFn: (v: string | number) => HumanizeResult,
153	    odfMetricResult: PrometheusResponse,
154	    scaleMetricResult: PrometheusResponse,
155	    system: StorageSystemKind,
156	    isSANSystem: boolean,
157	    isRemoteClusterSystem: boolean
158	  ) => {
159	    const isLatencyMetric = humanizeFn === humanizeLatency;
160	
161	    let value: string | undefined;
162	
163	    const aggregateMetrics = (
164	      metrics: { value?: [number, string] }[]
165	    ): string | undefined => {
166	      if (!metrics.length) {
167	        return undefined;
168	      }
169	      const sum = metrics.reduce((acc, item) => {
170	        const metricValue = Number(item?.value?.[1] || 0);
171	        return acc + metricValue;
172	      }, 0);
173	      return isLatencyMetric
174	        ? (sum / metrics.length).toString()
175	        : sum.toString();
176	    };
177	
178	    if (isSANSystem && scaleMetricResult?.data?.result) {
179	      const sanClusterName =
180	        system.metadata?.annotations?.[SAN_CLUSTER_NAME_ANNOTATION];
181	      const matchingMetrics = scaleMetricResult.data.result.filter(
182	        (item) => item?.metric?.gpfs_cluster_name === sanClusterName
183	      );
184	      value = aggregateMetrics(matchingMetrics);
185	    } else if (isRemoteClusterSystem && scaleMetricResult?.data?.result) {
186	      const filesystemNames =
187	        filesystemsByRemoteCluster[system.spec.name] || [];
188	      const matchingMetrics = scaleMetricResult.data.result.filter((item) =>
189	        filesystemNames.includes(item?.metric?.gpfs_fs_name)
190	      );
191	      value = aggregateMetrics(matchingMetrics);
192	    } else if (odfMetricResult?.data?.result) {
193	      const metric = odfMetricResult.data.result.find(
194	        (item) => item?.metric?.managedBy === system.spec.name
195	      );
196	      value = metric?.value?.[1];
197	    }
198	
199	    if (value == null) {
200	      return EMPTY_METRIC;
201	    }
202	    return humanizeFn(value);
203	  };
204	
205	  const getMaxMetricValue = (
206	    metrics: { value?: [number, string] }[]
207	  ): number | undefined => {
208	    const values = metrics
209	      .map((metric) => Number(metric?.value?.[1]))
210	      .filter((value) => Number.isFinite(value));
211	    return values.length ? Math.max(...values) : undefined;
212	  };
213	
214	  const getSystemHealthStatus = (
215	    system: StorageSystemKind,
216	    isSANSystem: boolean,
217	    isRemoteClusterSystem: boolean
218	  ): string | undefined => {
219	    if (!(isSANSystem || isRemoteClusterSystem)) {
220	      return undefined;
221	    }
222	
223	    if (!scaleMetrics.health?.data?.result?.length) {
224	      return undefined;
225	    }
226	
227	    let matchingMetrics: { value?: [number, string] }[];
228	
229	    if (isSANSystem) {
230	      const sanClusterName =
231	        system.metadata?.annotations?.[SAN_CLUSTER_NAME_ANNOTATION];
232	      matchingMetrics = scaleMetrics.health.data.result.filter(
233	        (item) => item?.metric?.gpfs_cluster_name === sanClusterName
234	      );
235	    } else {
236	      const filesystemNames =
237	        filesystemsByRemoteCluster[system.spec.name] || [];
238	      matchingMetrics = scaleMetrics.health.data.result.filter((item) =>
239	        filesystemNames.includes(item?.metric?.gpfs_health_entity)
240	      );
241	    }
242	
243	    return getHealthStatusFromMetric(getMaxMetricValue(matchingMetrics));
244	  };
245	
246	  return systems.reduce<SystemMetrics>((acc, curr) => {
247	    const { kind } = getGVK(curr.spec.kind);
248	    const isSANSystem = kind === ClusterModel.kind.toLowerCase();
249	    const isRemoteClusterSystem =
250	      kind === RemoteClusterModel.kind.toLowerCase();
251	
252	    acc[`${getName(curr)}${getNamespace(curr)}`] = {
253	      rawCapacity: getHumanizedMetric(
254	        humanizeBinaryBytes,
255	        odfMetrics.rawCapacity,
256	        scaleMetrics.rawCapacity,
257	        curr,
258	        isSANSystem,
259	        isRemoteClusterSystem
260	      ),
261	      usedCapacity: getHumanizedMetric(
262	        humanizeBinaryBytes,
263	        odfMetrics.usedCapacity,
264	        scaleMetrics.usedCapacity,
265	        curr,
266	        isSANSystem,
267	        isRemoteClusterSystem
268	      ),
269	      iops: getHumanizedMetric(
270	        humanizeIOPS,
271	        odfMetrics.iops,
272	        scaleMetrics.iops,
273	        curr,
274	        isSANSystem,
275	        isRemoteClusterSystem
276	      ),
277	      throughput: getHumanizedMetric(
278	        humanizeDecimalBytesPerSec,
279	        odfMetrics.throughput,
280	        scaleMetrics.throughput,
281	        curr,
282	        isSANSystem,
283	        isRemoteClusterSystem
284	      ),
285	      latency: getHumanizedMetric(
286	        humanizeLatency,
287	        odfMetrics.latency,
288	        scaleMetrics.latency,
289	        curr,
290	        isSANSystem,
291	        isRemoteClusterSystem
292	      ),
293	      healthStatus: getSystemHealthStatus(
294	        curr,
295	        isSANSystem,
296	        isRemoteClusterSystem
297	      ),
298	    };
299	    return acc;
300	  }, {});
301	};
302	
303	type CustomData = {
304	  infrastructure: InfrastructureKind;
305	  isLSOInstalled: boolean;
306	  normalizedMetrics: ReturnType<typeof normalizeMetrics>;
307	  storageClusters: StorageClusterKind[];
308	};
309	
310	type StorageSystemNewPageProps = {
311	  data: StorageSystemKind[];
312	  unfilteredData: StorageSystemKind[];
313	  loaded: boolean;
314	  loadError: any;
315	  rowData: any;
316	};
317	
318	const tableColumnInfo = [
319	  { className: '', id: 'name' },
320	  { className: '', id: 'status' },
321	  {
322	    className: classNames('pf-m-hidden', 'pf-m-visible-on-sm'),
323	    id: 'rawCapacity',
324	  },
325	  {
326	    className: classNames('pf-m-hidden', 'pf-m-visible-on-md'),
327	    id: 'usedCapacity',
328	  },
329	  {
330	    className: classNames('pf-m-hidden', 'pf-m-visible-on-lg'),
331	    id: 'iops',
332	  },
333	  {
334	    className: classNames('pf-m-hidden', 'pf-m-visible-on-xl'),
335	    id: 'throughput',
336	  },
337	  { className: classNames('pf-m-hidden', 'pf-m-visible-on-xl'), id: 'latency' },
338	  { className: Kebab.columnClass, id: '' },
339	];
340	
341	const StorageSystemList: React.FC<StorageSystemNewPageProps> = (props) => {
342	  const { t } = useCustomTranslation();
343	  const storageSystemTableColumns = React.useMemo<
344	    TableColumn<StorageSystemKind>[]
345	  >(
346	    () => [
347	      {
348	        title: t('Name'),
349	        sort: 'metadata.name',
350	        transforms: [sortable],
351	        props: {
352	          className: tableColumnInfo[0].className,
353	        },
354	        id: tableColumnInfo[0].id,
355	      },
356	      {
357	        title: t('Status'),
358	        transforms: [wrappable],
359	        props: {
360	          className: tableColumnInfo[1].className,
361	        },
362	        id: tableColumnInfo[1].id,
363	      },
364	      {
365	        title: t('Raw Capacity'),
366	        transforms: [wrappable],
367	        props: {
368	          className: tableColumnInfo[2].className,
369	        },
370	        id: tableColumnInfo[2].id,
371	      },
372	      {
373	        title: t('Used capacity'),
374	        transforms: [wrappable],
375	        props: {
376	          className: tableColumnInfo[3].className,
377	        },
378	        id: tableColumnInfo[3].id,
379	      },
380	      {
381	        title: t('IOPS'),
382	        transforms: [wrappable],
383	        props: {
384	          className: tableColumnInfo[4].className,
385	        },
386	        id: tableColumnInfo[4].id,
387	      },
388	      {
389	        title: t('Throughput'),
390	        transforms: [wrappable],
391	        props: {
392	          className: tableColumnInfo[5].className,
393	        },
394	        id: tableColumnInfo[5].id,
395	      },
396	      {
397	        title: t('Latency'),
398	        props: {
399	          className: tableColumnInfo[6].className,
400	        },
401	        id: tableColumnInfo[6].id,
402	      },
403	      {
404	        title: '',
405	        props: {
406	          className: tableColumnInfo[7].className,
407	        },
408	        id: tableColumnInfo[7].id,
409	      },
410	    ],
411	    [t]
412	  );
413	
414	  const [columns] = useActiveColumns({
415	    columns: storageSystemTableColumns,
416	    showNamespaceOverride: false,
417	    columnManagementID: null,
418	  });
419	
420	  return (
421	    <VirtualizedTable
422	      {...props}
423	      aria-label={t('Storage systems')}
424	      columns={columns}
425	      Row={StorageSystemRow}
426	    />
427	  );
428	};
429	
430	const getModelOfExternalSystem = (obj: StorageSystemKind): K8sModel => {
431	  const { kind } = getGVK(obj.spec.kind);
432	  if (kind === IBMFlashSystemModel.kind.toLowerCase()) {
433	    return IBMFlashSystemModel;
434	  }
435	  if (kind === StorageClusterModel.kind.toLowerCase()) {
436	    return StorageClusterModel;
437	  }
438	  if (kind === RemoteClusterModel.kind.toLowerCase()) {
439	    return RemoteClusterModel;
440	  }
441	  if (kind === ClusterModel.kind.toLowerCase()) {
442	    return ClusterModel;
443	  }
444	  throw new Error(`Unknown external system kind: ${kind}`);
445	};
446	
447	const StorageSystemRow: React.FC<RowProps<StorageSystemKind, CustomData>> = ({
448	  obj,
449	  activeColumnIDs,
450	  rowData,
451	}) => {
452	  const { t } = useCustomTranslation();
453	  const { apiGroup, apiVersion, kind } = getGVK(obj.spec.kind);
454	  const systemKind = referenceForGroupVersionKind(apiGroup)(apiVersion)(kind);
455	  const systemName = getName(obj);
456	  const systemNamespace = getNamespace(obj);
457	  const { normalizedMetrics } = rowData;
458	  const { customActions, hiddenActions } = getActions(obj, t);
459	
460	  const metrics =
461	    normalizedMetrics?.normalizedMetrics?.[`${systemName}${systemNamespace}`];
462	
463	  const { rawCapacity, usedCapacity, iops, throughput, latency, healthStatus } =
464	    metrics || {};
465	
466	  const isSANSystem = kind === ClusterModel.kind.toLowerCase();
467	  const isRemoteCluster = kind === RemoteClusterModel.kind.toLowerCase();
468	
469	  const getStatusComponent = (): React.ReactNode => {
470	    if (obj?.metadata?.deletionTimestamp) {
471	      return <Status status="Terminating" />;
472	    }
473	    if ((isSANSystem || isRemoteCluster) && healthStatus) {
474	      return <Status status={healthStatus} />;
475	    }
476	    return <OperandStatus operand={obj} />;
477	  };
478	
479	  return (
480	    <>
481	      <TableData {...tableColumnInfo[0]} activeColumnIDs={activeColumnIDs}>
482	        <ODFSystemLink
483	          kind={systemKind}
484	          systemName={systemName}
485	          providerName={systemName}
486	        />
487	      </TableData>
488	      <TableData {...tableColumnInfo[1]} activeColumnIDs={activeColumnIDs}>
489	        {getStatusComponent()}
490	      </TableData>
491	      <TableData {...tableColumnInfo[2]} activeColumnIDs={activeColumnIDs}>
492	        {rawCapacity?.string || '-'}
493	      </TableData>
494	      <TableData {...tableColumnInfo[3]} activeColumnIDs={activeColumnIDs}>
495	        {usedCapacity?.string || '-'}
496	      </TableData>
497	      <TableData {...tableColumnInfo[4]} activeColumnIDs={activeColumnIDs}>
498	        {iops?.string || '-'}
499	      </TableData>
500	      <TableData {...tableColumnInfo[5]} activeColumnIDs={activeColumnIDs}>
501	        {throughput?.string || '-'}
502	      </TableData>
503	      <TableData {...tableColumnInfo[6]} activeColumnIDs={activeColumnIDs}>
504	        {latency?.string || '-'}
505	      </TableData>
506	      <TableData {...tableColumnInfo[7]} activeColumnIDs={activeColumnIDs}>
507	        <Kebab
508	          customKebabItems={customActions}
509	          hideItems={hiddenActions}
510	          extraProps={{
511	            resource: obj,
512	            resourceModel: getModelOfExternalSystem(obj),
513	          }}
514	          customLabel={ODFStorageSystem.label}
515	        />
516	      </TableData>
517	    </>
518	  );
519	};
520	
521	export const StorageSystemListPage: React.FC = () => {
522	  const { t } = useCustomTranslation();
523	
524	  const launchModal = useModal();
525	  const isFDF = useFlag(FDF_FLAG);
526	
527	  const { odfNamespace, isODFNsLoaded, odfNsLoadError } =
528	    useODFNamespaceSelector();
529	
530	  const [storageSystems, loaded, loadError] = useWatchStorageSystems(true);
531	  const [data, filteredData, onFilterChange] =
532	    useListPageFilter(storageSystems);
533	
534	  const prometheusBasePath = usePrometheusBasePath();
535	
536	  const [latency] = useCustomPrometheusPoll({
537	    endpoint: PrometheusEndpoint.QUERY,
538	    query: ODF_QUERIES[ODFQueries.LATENCY],
539	    basePath: prometheusBasePath,
540	  });
541	  const [iops] = useCustomPrometheusPoll({
542	    endpoint: PrometheusEndpoint.QUERY,
543	    query: ODF_QUERIES[ODFQueries.IOPS],
544	    basePath: prometheusBasePath,
545	  });
546	  const [throughput] = useCustomPrometheusPoll({
547	    endpoint: PrometheusEndpoint.QUERY,
548	    query: ODF_QUERIES[ODFQueries.THROUGHPUT],
549	    basePath: prometheusBasePath,
550	  });
551	  const [rawCapacity] = useCustomPrometheusPoll({
552	    endpoint: PrometheusEndpoint.QUERY,
553	    query: ODF_QUERIES[ODFQueries.RAW_CAPACITY],
554	    basePath: prometheusBasePath,
555	  });
556	  const [usedCapacity] = useCustomPrometheusPoll({
557	    endpoint: PrometheusEndpoint.QUERY,
558	    query: ODF_QUERIES[ODFQueries.USED_CAPACITY],
559	    basePath: prometheusBasePath,
560	  });
561	
562	  const scaleQueries = React.useMemo(
563	    () =>
564	      isFDF
565	        ? {
566	            latency: SCALE_QUERIES[ScaleQueries.LATENCY],
567	            iops: SCALE_QUERIES[ScaleQueries.IOPS],
568	            throughput: SCALE_QUERIES[ScaleQueries.THROUGHPUT],
569	            rawCapacity: SCALE_QUERIES[ScaleQueries.RAW_CAPACITY],
570	            usedCapacity: SCALE_QUERIES[ScaleQueries.USED_CAPACITY],
571	            health: SCALE_QUERIES[ScaleQueries.HEALTH],
572	          }
573	        : null,
574	    [isFDF]
575	  );
576	
577	  const [scaleLatency] = useCustomPrometheusPoll({
578	    endpoint: PrometheusEndpoint.QUERY,
579	    query: scaleQueries?.latency,
580	    basePath: prometheusBasePath,
581	  });
582	  const [scaleIops] = useCustomPrometheusPoll({
583	    endpoint: PrometheusEndpoint.QUERY,
584	    query: scaleQueries?.iops,
585	    basePath: prometheusBasePath,
586	  });
587	  const [scaleThroughput] = useCustomPrometheusPoll({
588	    endpoint: PrometheusEndpoint.QUERY,
589	    query: scaleQueries?.throughput,
590	    basePath: prometheusBasePath,
591	  });
592	  const [scaleRawCapacity] = useCustomPrometheusPoll({
593	    endpoint: PrometheusEndpoint.QUERY,
594	    query: scaleQueries?.rawCapacity,
595	    basePath: prometheusBasePath,
596	  });
597	  const [scaleUsedCapacity] = useCustomPrometheusPoll({
598	    endpoint: PrometheusEndpoint.QUERY,
599	    query: scaleQueries?.usedCapacity,
600	    basePath: prometheusBasePath,
601	  });
602	  const [scaleHealth] = useCustomPrometheusPoll({
603	    endpoint: PrometheusEndpoint.QUERY,
604	    query: scaleQueries?.health,
605	    basePath: prometheusBasePath,
606	  });
607	
608	  const [infrastructure] = useK8sGet<InfrastructureKind>(
609	    InfrastructureModel,
610	    DEFAULT_INFRASTRUCTURE
611	  );
612	  const [storageClusters] = useK8sWatchResource<StorageClusterKind[]>(
613	    storageClusterResource
614	  );
615	
616	  const filesystemResource = isFDF
617	    ? {
618	        kind: referenceForModel(FileSystemModel),
619	        isList: true,
620	        namespaced: false,
621	      }
622	    : null;
623	
624	  const [filesystems, filesystemsLoaded] =
625	    useK8sWatchResource<FileSystemKind[]>(filesystemResource);
626	
627	  const filesystemsByRemoteCluster = React.useMemo(() => {
628	    if (!isFDF || !filesystemsLoaded || !filesystems) {
629	      return {};
630	    }
631	    return filesystems.reduce<FilesystemsByRemoteCluster>((acc, fs) => {
632	      const remoteClusterName = fs.spec?.remote?.cluster;
633	      if (!remoteClusterName) {
634	        return acc;
635	      }
636	      // SAN exporter uses the K8s Filesystem resource name as gpfs_fs_name.
637	      const filesystemName = getName(fs);
638	      acc[remoteClusterName] = [
639	        ...(acc[remoteClusterName] || []),
640	        filesystemName,
641	      ];
642	      return acc;
643	    }, {});
644	  }, [isFDF, filesystems, filesystemsLoaded]);
645	
646	  const normalizedMetrics = React.useMemo(
647	    () => ({
648	      normalizedMetrics: normalizeMetrics(
649	        data as StorageSystemKind[],
650	        {
651	          latency,
652	          throughput,
653	          rawCapacity,
654	          usedCapacity,
655	          iops,
656	        },
657	        {
658	          latency: scaleLatency,
659	          throughput: scaleThroughput,
660	          rawCapacity: scaleRawCapacity,
661	          usedCapacity: scaleUsedCapacity,
662	          iops: scaleIops,
663	          health: scaleHealth,
664	        },
665	        filesystemsByRemoteCluster
666	      ),
667	    }),
668	    [
669	      data,
670	      iops,
671	      latency,
672	      rawCapacity,
673	      throughput,
674	      usedCapacity,
675	      scaleIops,
676	      scaleLatency,
677	      scaleRawCapacity,
678	      scaleThroughput,
679	      scaleUsedCapacity,
680	      scaleHealth,
681	      filesystemsByRemoteCluster,
682	    ]
683	  );
684	
685	  const [lsoCSV, lsoCSVLoaded, lsoCSVLoadError] = useFetchCsv({
686	    specName: LSO_OPERATOR,
687	  });
688	
689	  const isLSOInstalled =
690	    lsoCSVLoaded && !lsoCSVLoadError && isCSVSucceeded(lsoCSV);
691	
692	  return (
693	    <>
694	      <ListPageHeader title={t('External systems')}>
695	        {odfNamespace && (
696	          <Button
697	            variant="primary"
698	            onClick={() => {
699	              launchModal(ExternalSystemsSelectModal, {});
700	            }}
701	          >
702	            {t('Connect external system')}
703	          </Button>
704	        )}
705	      </ListPageHeader>
706	      <ListPageBody>
707	        <ListPageFilter
708	          data={data}
709	          loaded={loaded && isODFNsLoaded}
