 57	  useK8sWatchResource,
 58	  useListPageFilter,
 59	  useModal,
 60	  VirtualizedTable,
 61	} from '@openshift-console/dynamic-plugin-sdk';
 62	import classNames from 'classnames';
 63	import * as _ from 'lodash-es';
 64	import { Button } from '@patternfly/react-core';
 65	import { sortable, wrappable } from '@patternfly/react-table';
 66	import {
 67	  ODF_QUERIES,
 68	  ODFQueries,
 69	  SCALE_QUERIES,
 70	  ScaleQueries,
 71	  ScaleHealthStatus,
 72	} from '../../queries';
 73	import { useODFNamespaceSelector } from '../../redux';
 74	import { FileSystemKind } from '../../types/scale';
 75	import { OperandStatus } from '../utils';
 76	import { getActions } from './actions';
 77	import ODFSystemLink from './system-link';
 78	
 79	type SystemMetrics = {
 80	  [systemNameAndNamespace: string]: {
 81	    rawCapacity: HumanizeResult;
 82	    usedCapacity: HumanizeResult;
 83	    iops: HumanizeResult;
 84	    throughput: HumanizeResult;
 85	    latency: HumanizeResult;
 86	    healthStatus?: string;
 87	  };
 88	};
 89	
 90	type MetricSet = {
 91	  latency: PrometheusResponse;
 92	  throughput: PrometheusResponse;
 93	  rawCapacity: PrometheusResponse;
 94	  usedCapacity: PrometheusResponse;
 95	  iops: PrometheusResponse;
 96	  health?: PrometheusResponse;
 97	};
 98	
 99	type FilesystemsByRemoteCluster = {
100	  [remoteClusterName: string]: string[];
101	};
102	
103	const EMPTY_METRIC: HumanizeResult = { string: '-', value: 0, unit: '' };
104	
105	const getHealthStatusFromMetric = (
106	  healthValue: number | undefined
107	): string | undefined => {
108	  if (healthValue === undefined || Number.isNaN(healthValue)) {
109	    return undefined;
110	  }
111	  if (healthValue <= ScaleHealthStatus.HEALTHY) {
112	    return 'Ready';
113	  }
114	  if (healthValue <= ScaleHealthStatus.DEGRADED) {
115	    return 'Warning';
116	  }
117	  return 'Error';
118	};
119	
120	type MetricNormalize = (
121	  systems: StorageSystemKind[],
122	  odfMetrics: MetricSet,
123	  scaleMetrics: MetricSet,
124	  filesystemsByRemoteCluster: FilesystemsByRemoteCluster
125	) => SystemMetrics;
126	
127	export const normalizeMetrics: MetricNormalize = (
128	  systems,
129	  odfMetrics,
130	  scaleMetrics,
131	  filesystemsByRemoteCluster
132	) => {
133	  if (_.isEmpty(systems)) {
134	    return {};
135	  }
136	
137	  const hasMetrics = (metrics: MetricSet): boolean =>
138	    !!(
139	      metrics.latency ||
140	      metrics.throughput ||
141	      metrics.rawCapacity ||
142	      metrics.usedCapacity ||
143	      metrics.iops ||
144	      metrics.health
145	    );
146	
147	  if (!hasMetrics(odfMetrics) && !hasMetrics(scaleMetrics)) {
148	    return {};
149	  }
150	
151	  const getHumanizedMetric = (
152	    humanizeFn: (v: string | number) => HumanizeResult,
153	    odfMetricResult: PrometheusResponse,
154	    scaleMetricResult: PrometheusResponse,
155	    system: StorageSystemKind,
156	    isSANSystem: boolean,
157	    isRemoteClusterSystem: boolean
158	  ) => {
159	    const isLatencyMetric = humanizeFn === humanizeLatency;
160	
161	    let value: string | undefined;
162	
163	    const aggregateMetrics = (
164	      metrics: { value?: [number, string] }[]
165	    ): string | undefined => {
166	      if (!metrics.length) {
167	        return undefined;
168	      }
169	      const sum = metrics.reduce((acc, item) => {
170	        const metricValue = Number(item?.value?.[1] || 0);
171	        return acc + metricValue;
172	      }, 0);
173	      return isLatencyMetric
174	        ? (sum / metrics.length).toString()
175	        : sum.toString();
176	    };
177	
178	    if (isSANSystem && scaleMetricResult?.data?.result) {
179	      const sanClusterName =
180	        system.metadata?.annotations?.[SAN_CLUSTER_NAME_ANNOTATION];
181	      const matchingMetrics = scaleMetricResult.data.result.filter(
182	        (item) => item?.metric?.gpfs_cluster_name === sanClusterName
183	      );
184	      value = aggregateMetrics(matchingMetrics);
185	    } else if (isRemoteClusterSystem && scaleMetricResult?.data?.result) {
186	      const filesystemNames =
187	        filesystemsByRemoteCluster[system.spec.name] || [];
188	      const matchingMetrics = scaleMetricResult.data.result.filter((item) =>
189	        filesystemNames.includes(item?.metric?.gpfs_fs_name)
190	      );
191	      value = aggregateMetrics(matchingMetrics);
192	    } else if (odfMetricResult?.data?.result) {
193	      const metric = odfMetricResult.data.result.find(
194	        (item) => item?.metric?.managedBy === system.spec.name
195	      );
196	      value = metric?.value?.[1];
197	    }
198	
199	    if (value == null) {
200	      return EMPTY_METRIC;
201	    }
202	    return humanizeFn(value);
203	  };
204	
205	  const getMaxMetricValue = (
206	    metrics: { value?: [number, string] }[]
207	  ): number | undefined => {
208	    const values = metrics
209	      .map((metric) => Number(metric?.value?.[1]))
210	      .filter((value) => Number.isFinite(value));
211	    return values.length ? Math.max(...values) : undefined;
212	  };
213	
214	  const getSystemHealthStatus = (
215	    system: StorageSystemKind,
216	    isSANSystem: boolean,
217	    isRemoteClusterSystem: boolean
218	  ): string | undefined => {
219	    if (!(isSANSystem || isRemoteClusterSystem)) {
220	      return undefined;
221	    }
222	
223	    if (!scaleMetrics.health?.data?.result?.length) {
224	      return undefined;
225	    }
226	
227	    let matchingMetrics: { value?: [number, string] }[];
228	
229	    if (isSANSystem) {
230	      const sanClusterName =
231	        system.metadata?.annotations?.[SAN_CLUSTER_NAME_ANNOTATION];
232	      matchingMetrics = scaleMetrics.health.data.result.filter(
233	        (item) => item?.metric?.gpfs_cluster_name === sanClusterName
234	      );
235	    } else {
236	      const filesystemNames =
237	        filesystemsByRemoteCluster[system.spec.name] || [];
238	      matchingMetrics = scaleMetrics.health.data.result.filter((item) =>
239	        filesystemNames.includes(item?.metric?.gpfs_health_entity)
240	      );
241	    }
242	
243	    return getHealthStatusFromMetric(getMaxMetricValue(matchingMetrics));
